3	
4	import { assemblePrompt } from "./promptAssembly.js";
5	import type { Retrieved } from "./retriever.js";
6	
7	function makeRetrieved(over: Partial<Retrieved> & { id: string }): Retrieved {
8	  return {
9	    chunkId: over.id,
10	    text: over.text ?? `text for ${over.id}`,
11	    heading: over.heading ?? `Heading ${over.id}`,
12	    section: over.section,
13	    path: over.path ?? `corpus/${over.id}.md`,
14	    topics: over.topics ?? [],
15	    kind: over.kind ?? "essay",
16	    score: over.score ?? 0.7,
17	    citeOkay: over.citeOkay ?? true,
18	  };
19	}
20	
21	/** Build a string that exceeds `target` tokens. */
22	function padToTokens(target: number): string {
23	  const seed = "lorem ipsum dolor sit amet consectetur adipiscing elit ";
24	  let s = "";
25	  while (countTokens(s) < target) {
26	    s += seed.repeat(20);
27	  }
28	  return s;
29	}
30	
31	describe("assemblePrompt", () => {
32	  const persona = "You are an assistant who speaks in the voice of M.Q.";
33	
34	  it("produces a well-formed system prompt with no retrieved block when retrieved is empty", async () => {
35	    const out = await assemblePrompt({
36	      persona,
37	      retrieved: [],
38	      history: [],
39	      userMessage: "hello",
40	    });
41	    expect(out.system).toContain(persona);
42	    expect(out.system).toContain("You answer using ONLY");
43	    expect(out.system).not.toContain("<retrieved_context>");
44	    expect(out.citations).toEqual([]);
45	    expect(out.messages).toEqual([{ role: "user", content: "hello" }]);
46	    expect(out.tokenBudget.max).toBe(16000);
47	    expect(out.tokenBudget.used).toBeGreaterThan(0);
48	  });
49	
50	  it("renders retrieved chunks with sequential [c1], [c2], ... ids", async () => {
51	    const retrieved = [
52	      makeRetrieved({ id: "alpha", score: 0.9, text: "alpha body" }),
53	      makeRetrieved({ id: "beta", score: 0.8, text: "beta body" }),
54	      makeRetrieved({ id: "gamma", score: 0.7, text: "gamma body" }),
55	    ];
56	    const out = await assemblePrompt({
57	      persona,
58	      retrieved,
59	      history: [],
60	      userMessage: "tell me",
61	    });
62	
63	    expect(out.system).toContain("<retrieved_context>");
64	    expect(out.system).toContain("</retrieved_context>");
65	    expect(out.system).toContain("[c1]");
66	    expect(out.system).toContain("[c2]");
67	    expect(out.system).toContain("[c3]");
68	    expect(out.system).toContain("alpha body");
69	    expect(out.system).toContain("beta body");
70	    expect(out.system).toContain("gamma body");
