72	    // Citations map [c1].. back to chunkIds in score-desc order.
73	    expect(out.citations).toEqual([
74	      { id: "c1", chunkId: "alpha", snippet: "alpha body" },
75	      { id: "c2", chunkId: "beta", snippet: "beta body" },
76	      { id: "c3", chunkId: "gamma", snippet: "gamma body" },
77	    ]);
78	
79	    // IDs are sequential and unique.
80	    const ids = out.citations.map((c) => c.id);
81	    expect(new Set(ids).size).toBe(ids.length);
82	    expect(ids).toEqual(["c1", "c2", "c3"]);
83	  });
