90	    ];
91	    const out = await assemblePrompt({
92	      persona,
93	      retrieved,
94	      history: [],
95	      userMessage: "?",
96	    });
97	    expect(out.citations.map((c) => c.chunkId)).toEqual([
98	      "high",
99	      "mid",
100	      "low",
101	    ]);
102	  });
