169	    const history: { role: "user" | "assistant"; content: string }[] = [
170	      { role: "user", content: "q1" },
171	      { role: "assistant", content: "a1" },
172	    ];
173	    const out = await assemblePrompt({
174	      persona,
175	      retrieved: [],
176	      history,
